+  );
+}
+
+function validateConfigValue(
+  option: Option,
+  key: string,
+  value: unknown,
+): void {
+  if (option.collect) {
+    if (!Array.isArray(value)) {
+      throw new ConfigValidationError(key, "an array");
+    }
+    value.forEach((entry) => validateConfigOptionValue(option, key, entry));
+    return;
+  }
+  if (Array.isArray(value)) {
+    throw new ConfigValidationError(key, "a scalar value");
+  }
+  validateConfigOptionValue(option, key, value);
+}
+
+function validateConfigOptionValue(
+  option: Option,
+  key: string,
+  value: unknown,
+): void {
+  const argument = option.args[0];
+  const expected = argument?.type ?? "boolean";
+  const valid = expected === "boolean"
+    ? typeof value === "boolean"
+    : expected === "number"
+    ? typeof value === "number" && Number.isFinite(value)
+    : expected === "integer"
+    ? typeof value === "number" && Number.isInteger(value)
+    : ["string", "file", "secret"].includes(expected)
+    ? typeof value === "string"
+    : true;
+  if (!valid) throw new ConfigValidationError(key, expected);
+}
