+const kebabToCamelCase = (key: string): string =>
+  key.replace(/-([a-zA-Z0-9])/g, (_, character: string) =>
+    character.toUpperCase()
+  );
+
+export function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): ConfigValues {
+  const result: ConfigValues = {};
+  for (const [key, child] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${kebabToCamelCase(key)}` : kebabToCamelCase(key);
+    if (isPlainObject(child)) {
+      Object.assign(result, flattenConfig(child, name));
+    } else {
+      result[name] = child;
+    }
+  }
+  return result;
+}
+
+export async function loadConfig(
+  options: ConfigOptions,
+): Promise<{ path?: string; values: ConfigValues }> {
+  const searchPaths = options.searchPaths?.length ? options.searchPaths : [cwd()];
+  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
+  let values: ConfigValues = {};
+  let path: string | undefined;
+
+  for (const searchPath of searchPaths) {
+    const found = await findConfig(searchPath, options.name, formats);
+    if (!found) continue;
+
+    const parsed = parseConfig(found.path, found.content, options.parser);
+    const flattened = flattenConfig(parsed);
+    if (!path) path = found.path;
+    values = { ...flattened, ...values };
+    if (!options.mergeConfigs) break;
+  }
+  return { path, values };
+}
+
+async function findConfig(path: string, name: string, formats: string[]) {
+  for (const format of formats) {
+    const filename = format === ".rc" ? `.${name}rc` : `${name}${format}`;
+    const filePath = resolve(join(path, filename));
+    const content = await readTextFile(filePath);
+    if (content !== undefined) return { path: filePath, content };
+  }
+}
+
+function parseConfig(
+  path: string,
+  content: string,
+  parser?: ConfigOptions["parser"],
+): Record<string, unknown> {
+  try {
+    const value = parser ? parser(content) : path.endsWith(".json")
+      ? JSON.parse(content)
+      : parseRc(content);
+    if (!isPlainObject(value)) throw new TypeError("Configuration must be an object.");
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const result: ConfigValues = {};
+  for (const sourceLine of content.split(/\\r?\
/)) {
+    const line = sourceLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const separator = line.indexOf("=");
+    if (separator < 1) throw new TypeError("Expected key=value.");
+    const key = line.slice(0, separator).trim();
+    let value = line.slice(separator + 1).trim();
+    if (value.startsWith('"')) {
